/**
 * Columns metadata from IacTable component.
 * @example
 * const columns = [
 *     { field: 'id', label: 'ID', width: '80px' },
 *     { field: 'name', label: 'Name', sortable: false },
 *     { field: 'inputReference', label: 'ISO Ref.', bgColor: (e) => this.getBgColor(e.field, e.rowData) }
 * ];
 * @author Pascal Font.
 */
export class IacTableColumn {
    constructor() {
        /**
         * Sortable column
         * @default: true
         */
        this.sortable = true;
    }
}
